const mongoose = require("mongoose");
const logger = require("../utils/logger");

/**
 * Old schemas used unique: true on sharedLinks.linkId, which makes MongoDB treat
 * absent linkIds as null — only one document was allowed. Remove any unique index
 * on that path, then sync indexes to match the current schema.
 */
const fixSharedLinksIndexes = async () => {
  const coll = mongoose.connection.collection("documents");
  let indexes;
  try {
    indexes = await coll.indexes();
  } catch (err) {
    logger.warn("Could not list indexes on documents collection:", err.message);
    return;
  }

  for (const idx of indexes) {
    const key = idx.key || {};
    const keyNames = Object.keys(key);
    if (keyNames.length !== 1 || key["sharedLinks.linkId"] !== 1) {
      continue;
    }
    if (!idx.unique) {
      continue;
    }
    try {
      await coll.dropIndex(idx.name);
      logger.info(`Dropped broken unique index "${idx.name}" on sharedLinks.linkId`);
    } catch (err) {
      logger.error(`Failed to drop index ${idx.name}:`, err.message);
    }
  }

  try {
    const Document = require("../models/Document");
    await Document.syncIndexes();
    logger.info("Document model indexes synced with schema");
  } catch (err) {
    logger.warn("Document.syncIndexes:", err.message);
  }
};

const connectDB = async () => {
  try {
    const mongoUri = process.env.MONGODB_URI || "mongodb://localhost:27017/docz";
    await mongoose.connect(mongoUri);
    logger.info(`MongoDB connected successfully (db: ${mongoose.connection.name})`);
    await fixSharedLinksIndexes();
  } catch (error) {
    logger.error("MongoDB connection error:", error.message);
    process.exit(1);
  }
};

mongoose.connection.on("disconnected", () => {
  logger.warn("MongoDB disconnected");
});

mongoose.connection.on("error", (err) => {
  logger.error("MongoDB error:", err);
});

module.exports = connectDB;
